int32_t& Int17Matrix3D::operator()(int x, int y, int z) {
    int index = GetIndex(x, y, z);
    // Perform bounds checking if necessary
    if (index >= max_index_) {
        throw std::out_of_range("Indices are out of bounds"); 
    }
    return array_[index];
}

// For const objects:
int32_t Int17Matrix3D::operator()(int x, int y, int z) const {
    int index = GetIndex(x, y, z);
    // Perform bounds checking if necessary
    if (index >= max_index_) {
        throw std::out_of_range("Indices are out of bounds"); 
    }
    return ToDecimal(array_, index);
}
```

