Int17Matrix3D& Int17Matrix3D::operator[](int index) {
  static int8_t counter = 0;
  if (counter == 0) {
    current_x_ = index;
  } else if (counter == 1) {
    current_y_ = index;
  } else {
    current_z_ = index;
  }

